module top_module(clk, rst, en, init, out);input clk,rst;
  input en, init;
  output reg out;
    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk, posedge rst or posedge dbg_halt)begin
    if (rst) out <= 0;
    else if (init) out <= 0;
    else if (en) out <= 1;
    else out <= out;
  end
endmodule
